@namespace Lumeo

<div class="@CssClass" @attributes="AdditionalAttributes">
    <CascadingValue Value="_context" IsFixed="false">
        <QueryBuilderGroup Group="EffectiveQuery" Depth="0" Parent="null" />
    </CascadingValue>

    @if (ShowJsonPreview)
    {
        <div class="mt-4 rounded-md border border-border/40 bg-muted/30">
            <div class="border-b border-border/40 px-3 py-1.5 text-xs font-medium text-muted-foreground">JSON</div>
            <pre class="overflow-x-auto p-3 text-xs text-foreground"><code>@QueryBuilderSerialization.ToJson(EffectiveQuery)</code></pre>
        </div>
    }
</div>

@code {
    /// <summary>The fields the consumer can build conditions against. Required.</summary>
    [Parameter] public IReadOnlyList<QueryField> Fields { get; set; } = Array.Empty<QueryField>();

    /// <summary>The query tree. Two-way bindable via <c>@bind-Query</c>. When <c>null</c> on
    /// first render, an empty root group (And, no rules) is created.</summary>
    [Parameter] public QueryGroup? Query { get; set; }
    [Parameter] public EventCallback<QueryGroup> QueryChanged { get; set; }

    /// <summary>When <c>true</c>, renders a read-only JSON view of the query below the builder.</summary>
    [Parameter] public bool ShowJsonPreview { get; set; }

    /// <summary>Maximum group nesting depth. The "Add group" button is disabled at this depth.</summary>
    [Parameter] public int MaxDepth { get; set; } = 5;

    /// <summary>When <c>false</c>, "Remove rule" / "Remove group" are hidden when it would leave
    /// a group empty (the root may always be empty).</summary>
    [Parameter] public bool AllowEmptyGroups { get; set; } = true;

    /// <summary>Optional override for how a rule's value editor renders. Receives the rule.
    /// When supplied, replaces the built-in per-type editor entirely (the consumer is then
    /// responsible for binding to <see cref="QueryRule.Value"/> and calling
    /// <c>NotifyChanged</c> via the cascaded context — see docs).</summary>
    [Parameter] public RenderFragment<QueryRule>? ValueEditorTemplate { get; set; }

    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private QueryBuilderContext _context = default!;

    private QueryGroup EffectiveQuery => Query ??= QueryGroup.CreateEmpty();

    private string CssClass => $"w-full text-sm {Class}".Trim();

    protected override void OnInitialized()
    {
        Query ??= QueryGroup.CreateEmpty();
        RebuildContext();
    }

    protected override void OnParametersSet()
    {
        Query ??= QueryGroup.CreateEmpty();
        RebuildContext();
    }

    private void RebuildContext()
    {
        _context = new QueryBuilderContext(
            Fields,
            MaxDepth,
            AllowEmptyGroups,
            ValueEditorTemplate,
            NotifyChanged);
    }

    private async Task NotifyChanged()
    {
        await QueryChanged.InvokeAsync(EffectiveQuery);
        StateHasChanged();
    }

    // --- Static helpers (re-exported for convenience) ---

    /// <summary>Serializes a query tree to indented JSON (System.Text.Json, camelCase, string enums).</summary>
    public static string ToJson(QueryGroup query) => QueryBuilderSerialization.ToJson(query);

    /// <summary>Parses a query tree from JSON produced by <see cref="ToJson"/>. Returns <c>null</c> on failure.</summary>
    public static QueryGroup? FromJson(string json) => QueryBuilderSerialization.FromJson(json);

    /// <summary>Compiles a query tree to a LINQ predicate. Returns <c>null</c> for an empty tree.</summary>
    public static System.Linq.Expressions.Expression<Func<T, bool>>? ToExpression<T>(QueryGroup query)
        => QueryBuilderSerialization.ToExpression<T>(query);

    /// <summary>Cascaded state shared with the recursive <see cref="QueryBuilderGroup"/> renderer.</summary>
    public sealed record QueryBuilderContext(
        IReadOnlyList<QueryField> Fields,
        int MaxDepth,
        bool AllowEmptyGroups,
        RenderFragment<QueryRule>? ValueEditorTemplate,
        Func<Task> NotifyChanged)
    {
        public QueryField? FindField(string name) => Fields.FirstOrDefault(f => f.Name == name);
    }
}

@namespace Lumeo
@inject Lumeo.Services.Localization.ILumeoLocalizer L

@{
    var isRoot = Depth == 0;
    var canNest = Depth < Ctx.MaxDepth;
}

<div class="@GroupClass" role="group" aria-label="@L[isRoot ? "QueryBuilder.QueryGroup" : "QueryBuilder.NestedQueryGroup"]" @attributes="AdditionalAttributes">
    <div class="flex flex-wrap items-center gap-2">
        <div class="inline-flex items-center rounded-md bg-muted p-0.5" role="radiogroup" aria-label="@L["QueryBuilder.Combinator"]">
            <button type="button"
                    role="radio"
                    aria-checked="@((Group.Combinator == QueryCombinator.And).ToString().ToLowerInvariant())"
                    class="@CombinatorPillClass(Group.Combinator == QueryCombinator.And)"
                    @onclick="@(() => SetCombinator(QueryCombinator.And))">
                AND
            </button>
            <button type="button"
                    role="radio"
                    aria-checked="@((Group.Combinator == QueryCombinator.Or).ToString().ToLowerInvariant())"
                    class="@CombinatorPillClass(Group.Combinator == QueryCombinator.Or)"
                    @onclick="@(() => SetCombinator(QueryCombinator.Or))">
                OR
            </button>
        </div>

        <Button Variant="Button.ButtonVariant.Outline" Size="Button.ButtonSize.Sm"
                OnClick="AddRule" aria-label="@L["QueryBuilder.AddRule"]">
            <Blazicon Svg="Lucide.Plus" class="h-3.5 w-3.5" />
            <span>Rule</span>
        </Button>

        <Button Variant="Button.ButtonVariant.Outline" Size="Button.ButtonSize.Sm"
                OnClick="AddGroup" Disabled="@(!canNest)" aria-label="@L["QueryBuilder.AddGroup"]">
            <Blazicon Svg="Lucide.FolderPlus" class="h-3.5 w-3.5" />
            <span>Group</span>
        </Button>

        <div class="ml-auto"></div>

        @if (!isRoot && CanRemoveSelf)
        {
            <Button Variant="Button.ButtonVariant.Ghost" Size="Button.ButtonSize.Icon"
                    OnClick="RemoveSelf" Class="h-7 w-7 text-muted-foreground hover:text-destructive"
                    aria-label="@L["QueryBuilder.RemoveGroup"]">
                <Blazicon Svg="Lucide.X" class="h-4 w-4" />
            </Button>
        }
    </div>

    @if (Group.Rules.Count == 0)
    {
        <p class="px-1 py-2 text-xs text-muted-foreground">No conditions yet. Add a rule or a group.</p>
    }
    else
    {
        <div class="space-y-2">
            @foreach (var node in Group.Rules.ToList())
            {
                @if (node is QueryRule rule)
                {
                    <div class="flex flex-wrap items-center gap-2 rounded-md border border-border/40 bg-card p-2">
                        @* Field picker *@
                        <select class="@SelectClass" value="@rule.Field" @onchange="@(e => OnFieldChanged(rule, e.Value?.ToString()))" aria-label="@L["QueryBuilder.Field"]">
                            @if (string.IsNullOrEmpty(rule.Field))
                            {
                                <option value="" disabled selected>Select field…</option>
                            }
                            @foreach (var f in Ctx.Fields)
                            {
                                <option value="@f.Name" selected="@(f.Name == rule.Field)">@f.DisplayLabel</option>
                            }
                        </select>

                        @{
                            var field = string.IsNullOrEmpty(rule.Field) ? null : Ctx.FindField(rule.Field);
                        }
                        @if (field is not null)
                        {
                            @* Operator picker *@
                            <select class="@SelectClass" value="@rule.Operator" @onchange="@(e => OnOperatorChanged(rule, e.Value?.ToString()))" aria-label="@L["QueryBuilder.Operator"]">
                                @foreach (var op in field.EffectiveOperators)
                                {
                                    <option value="@op" selected="@(op == rule.Operator)">@QueryBuilderOperators.LabelFor(op)</option>
                                }
                            </select>

                            @* Value editor *@
                            @if (Ctx.ValueEditorTemplate is not null)
                            {
                                @Ctx.ValueEditorTemplate(rule)
                            }
                            else if (!QueryBuilderOperators.NoValueOperators.Contains(rule.Operator))
                            {
                                @RenderValueEditor(field, rule, isSecond: false)
                                @if (QueryBuilderOperators.RangeOperators.Contains(rule.Operator))
                                {
                                    <span class="text-xs text-muted-foreground">and</span>
                                    @RenderValueEditor(field, rule, isSecond: true)
                                }
                            }
                        }

                        <div class="ml-auto"></div>

                        @if (CanRemoveChild)
                        {
                            <Button Variant="Button.ButtonVariant.Ghost" Size="Button.ButtonSize.Icon"
                                    OnClick="@(() => RemoveNode(rule))" Class="h-7 w-7 text-muted-foreground hover:text-destructive"
                                    aria-label="@L["QueryBuilder.RemoveRule"]">
                                <Blazicon Svg="Lucide.X" class="h-4 w-4" />
                            </Button>
                        }
                    </div>
                }
                else if (node is QueryGroup childGroup)
                {
                    <QueryBuilderGroup Group="childGroup" Depth="@(Depth + 1)" Parent="Group" />
                }
            }
        </div>
    }
</div>

@code {
    [CascadingParameter] public QueryBuilder.QueryBuilderContext Ctx { get; set; } = default!;

    [Parameter, EditorRequired] public QueryGroup Group { get; set; } = default!;
    [Parameter] public int Depth { get; set; }

    /// <summary>The parent group (null for the root) — used to support self-removal.</summary>
    [Parameter] public QueryGroup? Parent { get; set; }

    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private bool AllowEmpty => Ctx.AllowEmptyGroups;

    // Removing a child is allowed when empties are permitted, or when more than one child remains.
    private bool CanRemoveChild => AllowEmpty || Group.Rules.Count > 1;

    // Removing this (non-root) group is allowed when empties are permitted in the parent,
    // or when the parent would still have at least one child afterwards.
    private bool CanRemoveSelf => Parent is not null && (AllowEmpty || Parent.Rules.Count > 1);

    private const string GroupBase = "rounded-lg p-3 space-y-3";

    private string GroupClass => (Depth == 0
        ? $"{GroupBase} border border-border/40 bg-card {Class}"
        : $"{GroupBase} border-l-2 border-border/40 bg-muted/30 pl-4 {Class}").Trim();

    private const string SelectClass =
        "h-8 rounded-md border border-input bg-background px-2 text-sm text-foreground outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring disabled:cursor-not-allowed disabled:opacity-50";

    private const string InputClass =
        "h-8 w-40 rounded-md border border-input bg-background px-2 text-sm text-foreground outline-none placeholder:text-muted-foreground focus-visible:ring-[1.5px] focus-visible:ring-ring";

    private static string CombinatorPillClass(bool active) => active
        ? "inline-flex items-center justify-center rounded-[5px] bg-primary px-2.5 py-1 text-xs font-semibold text-primary-foreground focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1"
        : "inline-flex items-center justify-center rounded-[5px] px-2.5 py-1 text-xs font-medium text-muted-foreground hover:text-foreground focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1";

    private async Task SetCombinator(QueryCombinator c)
    {
        if (Group.Combinator == c) return;
        Group.Combinator = c;
        await Ctx.NotifyChanged();
    }

    private async Task AddRule()
    {
        var firstField = Ctx.Fields.FirstOrDefault();
        var rule = new QueryRule
        {
            Field = firstField?.Name ?? "",
            Operator = firstField?.EffectiveOperators.FirstOrDefault() ?? "",
            Value = DefaultValueFor(firstField)
        };
        Group.Rules.Add(rule);
        await Ctx.NotifyChanged();
    }

    private async Task AddGroup()
    {
        if (Depth >= Ctx.MaxDepth) return;
        Group.Rules.Add(QueryGroup.CreateEmpty());
        await Ctx.NotifyChanged();
    }

    private async Task RemoveNode(QueryNode node)
    {
        Group.Rules.Remove(node);
        await Ctx.NotifyChanged();
    }

    private async Task RemoveSelf()
    {
        if (Parent is null) return;
        Parent.Rules.Remove(Group);
        await Ctx.NotifyChanged();
    }

    private async Task OnFieldChanged(QueryRule rule, string? newField)
    {
        if (string.IsNullOrEmpty(newField) || rule.Field == newField) return;
        rule.Field = newField;
        var field = Ctx.FindField(newField);
        // Field type changed — reset operator to the field's first, clear value.
        rule.Operator = field?.EffectiveOperators.FirstOrDefault() ?? "";
        rule.Value = DefaultValueFor(field);
        rule.Value2 = null;
        await Ctx.NotifyChanged();
    }

    private async Task OnOperatorChanged(QueryRule rule, string? newOp)
    {
        if (string.IsNullOrEmpty(newOp) || rule.Operator == newOp) return;
        var wasRange = QueryBuilderOperators.RangeOperators.Contains(rule.Operator);
        rule.Operator = newOp;
        if (!QueryBuilderOperators.RangeOperators.Contains(newOp)) rule.Value2 = null;
        if (QueryBuilderOperators.NoValueOperators.Contains(newOp)) { rule.Value = null; rule.Value2 = null; }
        await Ctx.NotifyChanged();
    }

    private async Task SetValue(QueryRule rule, bool isSecond, object? value)
    {
        if (isSecond) rule.Value2 = value;
        else rule.Value = value;
        await Ctx.NotifyChanged();
    }

    private static object? DefaultValueFor(QueryField? field) => field?.Type switch
    {
        QueryFieldType.Boolean => false,
        _ => null
    };

    private static string? AsString(object? v) => v?.ToString();

    private RenderFragment RenderValueEditor(QueryField field, QueryRule rule, bool isSecond) => builder =>
    {
        var current = isSecond ? rule.Value2 : rule.Value;
        switch (field.Type)
        {
            case QueryFieldType.Number:
            {
                builder.OpenElement(0, "input");
                builder.AddAttribute(1, "type", "number");
                builder.AddAttribute(2, "class", InputClass + " w-28");
                builder.AddAttribute(3, "value", AsString(current));
                builder.AddAttribute(4, "aria-label", isSecond ? "Value (upper bound)" : "Value");
                builder.AddAttribute(5, "onchange",
                    Microsoft.AspNetCore.Components.EventCallback.Factory.Create<Microsoft.AspNetCore.Components.ChangeEventArgs>(
                        this, async e =>
                        {
                            var raw = e.Value?.ToString();
                            object? parsed = double.TryParse(raw, System.Globalization.NumberStyles.Any,
                                System.Globalization.CultureInfo.InvariantCulture, out var d) ? d : raw;
                            await SetValue(rule, isSecond, parsed);
                        }));
                builder.CloseElement();
                break;
            }
            case QueryFieldType.Date:
            {
                builder.OpenElement(0, "input");
                builder.AddAttribute(1, "type", "date");
                builder.AddAttribute(2, "class", InputClass);
                builder.AddAttribute(3, "value", AsString(current));
                builder.AddAttribute(4, "aria-label", isSecond ? "Date (upper bound)" : "Date");
                builder.AddAttribute(5, "onchange",
                    Microsoft.AspNetCore.Components.EventCallback.Factory.Create<Microsoft.AspNetCore.Components.ChangeEventArgs>(
                        this, async e => await SetValue(rule, isSecond, e.Value?.ToString())));
                builder.CloseElement();
                break;
            }
            case QueryFieldType.Boolean:
            {
                var isChecked = current is bool b && b;
                builder.OpenElement(0, "label");
                builder.AddAttribute(1, "class", "inline-flex items-center gap-1.5 text-sm text-foreground");
                builder.OpenElement(2, "input");
                builder.AddAttribute(3, "type", "checkbox");
                builder.AddAttribute(4, "class", "h-4 w-4 rounded border-input accent-primary");
                builder.AddAttribute(5, "checked", isChecked);
                builder.AddAttribute(6, "aria-label", "Value");
                builder.AddAttribute(7, "onchange",
                    Microsoft.AspNetCore.Components.EventCallback.Factory.Create<Microsoft.AspNetCore.Components.ChangeEventArgs>(
                        this, async e => await SetValue(rule, isSecond, e.Value is bool bb && bb)));
                builder.CloseElement();
                builder.AddContent(8, isChecked ? "true" : "false");
                builder.CloseElement();
                break;
            }
            case QueryFieldType.Select:
            {
                builder.OpenElement(0, "select");
                builder.AddAttribute(1, "class", SelectClass);
                builder.AddAttribute(2, "value", AsString(current));
                builder.AddAttribute(3, "aria-label", "Value");
                builder.AddAttribute(4, "onchange",
                    Microsoft.AspNetCore.Components.EventCallback.Factory.Create<Microsoft.AspNetCore.Components.ChangeEventArgs>(
                        this, async e => await SetValue(rule, isSecond, e.Value?.ToString())));
                if (string.IsNullOrEmpty(AsString(current)))
                {
                    builder.OpenElement(5, "option");
                    builder.AddAttribute(6, "value", "");
                    builder.AddAttribute(7, "disabled", true);
                    builder.AddAttribute(8, "selected", true);
                    builder.AddContent(9, "Select…");
                    builder.CloseElement();
                }
                var idx = 10;
                foreach (var (val, label) in field.Options ?? Array.Empty<(string, string)>())
                {
                    builder.OpenElement(idx++, "option");
                    builder.AddAttribute(idx++, "value", val);
                    builder.AddAttribute(idx++, "selected", val == AsString(current));
                    builder.AddContent(idx++, label);
                    builder.CloseElement();
                }
                builder.CloseElement();
                break;
            }
            default: // Text
            {
                builder.OpenElement(0, "input");
                builder.AddAttribute(1, "type", "text");
                builder.AddAttribute(2, "class", InputClass);
                builder.AddAttribute(3, "value", AsString(current));
                builder.AddAttribute(4, "placeholder", "Value");
                builder.AddAttribute(5, "aria-label", "Value");
                builder.AddAttribute(6, "onchange",
                    Microsoft.AspNetCore.Components.EventCallback.Factory.Create<Microsoft.AspNetCore.Components.ChangeEventArgs>(
                        this, async e => await SetValue(rule, isSecond, e.Value?.ToString())));
                builder.CloseElement();
                break;
            }
        }
    };
}

using System.Linq.Expressions;
using System.Text.Json;
using System.Text.Json.Serialization;

namespace Lumeo;

/// <summary>Boolean combinator for a <see cref="QueryGroup"/>.</summary>
public enum QueryCombinator
{
    And,
    Or
}

/// <summary>The data type of a <see cref="QueryField"/>. Drives the default operator
/// set and the built-in value editor rendered for a rule.</summary>
public enum QueryFieldType
{
    Text,
    Number,
    Date,
    Boolean,
    Select
}

/// <summary>
/// A field definition the consumer provides to <see cref="QueryBuilder"/>.
/// <see cref="Name"/> is the stable key written into produced rules;
/// <see cref="Label"/> is the human-facing text shown in the field picker.
/// </summary>
public sealed class QueryField
{
    /// <summary>Stable key written to <see cref="QueryRule.Field"/>. Required.</summary>
    public string Name { get; set; } = "";

    /// <summary>Human-facing label shown in the field picker. Falls back to <see cref="Name"/>.</summary>
    public string? Label { get; set; }

    /// <summary>The field's data type. Determines the default operator set and value editor.</summary>
    public QueryFieldType Type { get; set; } = QueryFieldType.Text;

    /// <summary>The operator keys allowed for this field. When <c>null</c>, the default
    /// set for <see cref="Type"/> is used (see <see cref="QueryBuilderOperators.DefaultsFor"/>).</summary>
    public IReadOnlyList<string>? Operators { get; set; }

    /// <summary>Options shown when <see cref="Type"/> is <see cref="QueryFieldType.Select"/>.
    /// Each tuple is <c>(Value, Label)</c>.</summary>
    public IReadOnlyList<(string Value, string Label)>? Options { get; set; }

    /// <summary>The display label — <see cref="Label"/> when set, otherwise <see cref="Name"/>.</summary>
    [JsonIgnore]
    public string DisplayLabel => string.IsNullOrEmpty(Label) ? Name : Label;

    /// <summary>The effective operator keys for this field.</summary>
    public IReadOnlyList<string> EffectiveOperators =>
        Operators is { Count: > 0 } ? Operators : QueryBuilderOperators.DefaultsFor(Type);
}

/// <summary>Base type for a node in a query tree — either a <see cref="QueryRule"/>
/// (a leaf condition) or a <see cref="QueryGroup"/> (a combinator with children).</summary>
[JsonDerivedType(typeof(QueryRule), "rule")]
[JsonDerivedType(typeof(QueryGroup), "group")]
public abstract class QueryNode
{
}

/// <summary>A single leaf condition: a field, an operator, and a comparison value.</summary>
public sealed class QueryRule : QueryNode
{
    /// <summary>The <see cref="QueryField.Name"/> this rule targets.</summary>
    public string Field { get; set; } = "";

    /// <summary>One of the field's allowed operator keys.</summary>
    public string Operator { get; set; } = "";

    /// <summary>The comparison value. Type depends on the field; for "between"-style
    /// operators this holds the lower bound and <see cref="Value2"/> holds the upper.</summary>
    public object? Value { get; set; }

    /// <summary>The second comparison value, used only by range operators ("between").</summary>
    public object? Value2 { get; set; }
}

/// <summary>A group: a <see cref="QueryCombinator"/> applied across a list of child
/// <see cref="QueryNode"/>s (rules and/or nested groups).</summary>
public sealed class QueryGroup : QueryNode
{
    public QueryCombinator Combinator { get; set; } = QueryCombinator.And;

    public List<QueryNode> Rules { get; set; } = new();

    /// <summary>Creates an empty root group (And, no rules).</summary>
    public static QueryGroup CreateEmpty() => new() { Combinator = QueryCombinator.And, Rules = new() };
}

/// <summary>Default operator sets per <see cref="QueryFieldType"/> and friendly display labels.</summary>
public static class QueryBuilderOperators
{
    public static readonly IReadOnlyList<string> TextDefaults =
        new[] { "=", "!=", "contains", "notContains", "startsWith", "endsWith", "isEmpty", "isNotEmpty" };

    public static readonly IReadOnlyList<string> NumberDefaults =
        new[] { "=", "!=", "<", "<=", ">", ">=", "between", "isNull", "isNotNull" };

    public static readonly IReadOnlyList<string> DateDefaults =
        new[] { "=", "!=", "<", "<=", ">", ">=", "between", "isNull", "isNotNull" };

    public static readonly IReadOnlyList<string> BooleanDefaults =
        new[] { "=", "!=" };

    public static readonly IReadOnlyList<string> SelectDefaults =
        new[] { "=", "!=", "in", "notIn", "isNull", "isNotNull" };

    /// <summary>Friendly display labels for operator keys.</summary>
    public static readonly IReadOnlyDictionary<string, string> Labels = new Dictionary<string, string>
    {
        ["="] = "equals",
        ["!="] = "not equals",
        ["<"] = "less than",
        ["<="] = "less than or equal",
        [">"] = "greater than",
        [">="] = "greater than or equal",
        ["contains"] = "contains",
        ["notContains"] = "does not contain",
        ["startsWith"] = "starts with",
        ["endsWith"] = "ends with",
        ["between"] = "between",
        ["in"] = "in",
        ["notIn"] = "not in",
        ["isEmpty"] = "is empty",
        ["isNotEmpty"] = "is not empty",
        ["isNull"] = "is null",
        ["isNotNull"] = "is not null"
    };

    /// <summary>Operators that take no value editor.</summary>
    public static readonly IReadOnlySet<string> NoValueOperators =
        new HashSet<string> { "isEmpty", "isNotEmpty", "isNull", "isNotNull" };

    /// <summary>Operators that take a second value editor (a range).</summary>
    public static readonly IReadOnlySet<string> RangeOperators = new HashSet<string> { "between" };

    public static IReadOnlyList<string> DefaultsFor(QueryFieldType type) => type switch
    {
        QueryFieldType.Text => TextDefaults,
        QueryFieldType.Number => NumberDefaults,
        QueryFieldType.Date => DateDefaults,
        QueryFieldType.Boolean => BooleanDefaults,
        QueryFieldType.Select => SelectDefaults,
        _ => TextDefaults
    };

    public static string LabelFor(string op) => Labels.TryGetValue(op, out var l) ? l : op;
}

/// <summary>Serialization + LINQ helpers for <see cref="QueryGroup"/> trees.</summary>
public static class QueryBuilderSerialization
{
    private static readonly JsonSerializerOptions JsonOptions = new()
    {
        WriteIndented = true,
        PropertyNamingPolicy = JsonNamingPolicy.CamelCase,
        Converters = { new JsonStringEnumConverter() }
    };

    private static readonly JsonSerializerOptions ReadOptions = new()
    {
        PropertyNamingPolicy = JsonNamingPolicy.CamelCase,
        PropertyNameCaseInsensitive = true,
        Converters = { new JsonStringEnumConverter() }
    };

    public static string ToJson(QueryGroup query) =>
        JsonSerializer.Serialize(query, JsonOptions);

    public static QueryGroup? FromJson(string json)
    {
        if (string.IsNullOrWhiteSpace(json)) return null;
        try
        {
            return JsonSerializer.Deserialize<QueryGroup>(json, ReadOptions);
        }
        catch (JsonException)
        {
            return null;
        }
    }

    /// <summary>
    /// Compiles a query tree to a LINQ predicate <c>Expression&lt;Func&lt;T,bool&gt;&gt;</c>.
    /// Returns <c>null</c> when the tree is empty (no rules anywhere). Unknown operators or
    /// missing properties throw <see cref="InvalidOperationException"/>. String comparisons
    /// for <c>contains</c>/<c>startsWith</c>/<c>endsWith</c> are case-insensitive (ordinal).
    /// </summary>
    public static Expression<Func<T, bool>>? ToExpression<T>(QueryGroup query)
    {
        var param = Expression.Parameter(typeof(T), "x");
        var body = BuildGroup<T>(query, param);
        return body is null ? null : Expression.Lambda<Func<T, bool>>(body, param);
    }

    private static Expression? BuildGroup<T>(QueryGroup group, ParameterExpression param)
    {
        var parts = new List<Expression>();
        foreach (var node in group.Rules)
        {
            Expression? part = node switch
            {
                QueryGroup g => BuildGroup<T>(g, param),
                QueryRule r => BuildRule<T>(r, param),
                _ => null
            };
            if (part is not null) parts.Add(part);
        }

        if (parts.Count == 0) return null;

        var acc = parts[0];
        for (var i = 1; i < parts.Count; i++)
        {
            acc = group.Combinator == QueryCombinator.And
                ? Expression.AndAlso(acc, parts[i])
                : Expression.OrElse(acc, parts[i]);
        }
        return acc;
    }

    private static Expression? BuildRule<T>(QueryRule rule, ParameterExpression param)
    {
        if (string.IsNullOrEmpty(rule.Field) || string.IsNullOrEmpty(rule.Operator)) return null;

        var prop = typeof(T).GetProperty(rule.Field,
            System.Reflection.BindingFlags.Public | System.Reflection.BindingFlags.Instance | System.Reflection.BindingFlags.IgnoreCase);
        if (prop is null)
            throw new InvalidOperationException($"Type '{typeof(T).Name}' has no public property '{rule.Field}'.");

        var member = Expression.Property(param, prop);
        var memberType = prop.PropertyType;
        var underlying = Nullable.GetUnderlyingType(memberType) ?? memberType;

        switch (rule.Operator)
        {
            case "isNull":
                return memberType.IsValueType && Nullable.GetUnderlyingType(memberType) is null
                    ? Expression.Constant(false)
                    : Expression.Equal(member, Expression.Constant(null, memberType));
            case "isNotNull":
                return memberType.IsValueType && Nullable.GetUnderlyingType(memberType) is null
                    ? Expression.Constant(true)
                    : Expression.NotEqual(member, Expression.Constant(null, memberType));
            case "isEmpty":
                return Expression.OrElse(
                    Expression.Equal(member, Expression.Constant(null, memberType)),
                    Expression.Equal(EnsureString(member), Expression.Constant("")));
            case "isNotEmpty":
                return Expression.AndAlso(
                    Expression.NotEqual(member, Expression.Constant(null, memberType)),
                    Expression.NotEqual(EnsureString(member), Expression.Constant("")));
        }

        if (rule.Operator is "contains" or "notContains" or "startsWith" or "endsWith")
        {
            var methodName = rule.Operator switch
            {
                "startsWith" => nameof(string.StartsWith),
                "endsWith" => nameof(string.EndsWith),
                _ => nameof(string.Contains)
            };
            var method = typeof(string).GetMethod(methodName, new[] { typeof(string), typeof(StringComparison) })!;
            var needle = Expression.Constant(rule.Value?.ToString() ?? "");
            var call = Expression.Call(EnsureString(member), method, needle, Expression.Constant(StringComparison.OrdinalIgnoreCase));
            var notNull = Expression.NotEqual(EnsureString(member), Expression.Constant(null, typeof(string)));
            var guarded = Expression.AndAlso(notNull, call);
            return rule.Operator == "notContains" ? Expression.Not(guarded) : guarded;
        }

        if (rule.Operator == "between")
        {
            var lo = Expression.Constant(ConvertValue(rule.Value, underlying), memberType);
            var hi = Expression.Constant(ConvertValue(rule.Value2, underlying), memberType);
            return Expression.AndAlso(
                Expression.GreaterThanOrEqual(member, lo),
                Expression.LessThanOrEqual(member, hi));
        }

        if (rule.Operator is "in" or "notIn")
        {
            var values = (rule.Value?.ToString() ?? "")
                .Split(',', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries);
            Expression? acc = null;
            foreach (var v in values)
            {
                var eq = Expression.Equal(member, Expression.Constant(ConvertValue(v, underlying), memberType));
                acc = acc is null ? eq : Expression.OrElse(acc, eq);
            }
            acc ??= Expression.Constant(false);
            return rule.Operator == "notIn" ? Expression.Not(acc) : acc;
        }

        var constant = Expression.Constant(ConvertValue(rule.Value, underlying), memberType);
        return rule.Operator switch
        {
            "=" => Expression.Equal(member, constant),
            "!=" => Expression.NotEqual(member, constant),
            "<" => Expression.LessThan(member, constant),
            "<=" => Expression.LessThanOrEqual(member, constant),
            ">" => Expression.GreaterThan(member, constant),
            ">=" => Expression.GreaterThanOrEqual(member, constant),
            _ => throw new InvalidOperationException($"Unsupported operator '{rule.Operator}'.")
        };
    }

    private static Expression EnsureString(Expression member) =>
        member.Type == typeof(string) ? member : Expression.Call(member, nameof(object.ToString), Type.EmptyTypes);

    private static object? ConvertValue(object? value, Type targetType)
    {
        if (value is null) return targetType.IsValueType ? Activator.CreateInstance(targetType) : null;
        if (targetType.IsInstanceOfType(value)) return value;

        var s = value as string ?? value.ToString();
        if (string.IsNullOrEmpty(s)) return targetType.IsValueType ? Activator.CreateInstance(targetType) : null;

        if (targetType.IsEnum) return Enum.Parse(targetType, s, ignoreCase: true);
        if (targetType == typeof(DateOnly)) return DateOnly.Parse(s, System.Globalization.CultureInfo.InvariantCulture);
        if (targetType == typeof(DateTime)) return DateTime.Parse(s, System.Globalization.CultureInfo.InvariantCulture);
        if (targetType == typeof(Guid)) return Guid.Parse(s);
        return Convert.ChangeType(s, targetType, System.Globalization.CultureInfo.InvariantCulture);
    }
}
